function startBowserFight() {
    let bossHP = 200;
    let spellCardActive = false;
    let defeated = false;
    const bullets = [];
    const canvas = document.createElement("canvas");
    canvas.id = "bowser-canvas";
    canvas.width = window.innerWidth;
    canvas.height = window.innerHeight;
    canvas.style.cssText = `
        position: fixed;
        top: 0; left: 0;
        width: 100%; height: 100%;
        pointer-events: none;
        z-index: 9999;
    `;
    document.body.appendChild(canvas);
    const ctx = canvas.getContext("2d");

    const bowserImg = new Image();
    bowserImg.src = "../img/default.gif";

    const byeImg = new Image();
    byeImg.src = "../img/bye.gif";

    const hammerImg = new Image();
    hammerImg.src = "../img/banhammer.png";

    const hammers = [];
    let bowserX = canvas.width / 2 - 128;
    let bowserY = 0;
    const SPEED = 3;
    let phase = 0; // 0=left, 1=down, 2=right, 3=down, 4=left, 5=down, 6=right, 7=down...

    function nextPhase() {
        phase = (phase + 1) % 4;
    }

    function spawnHammers() {
        if (defeated) return;
        const count = 1 + Math.floor(Math.random() * 2);
        for (let i = 0; i < count; i++) {
            hammers.push({
                x: bowserX + 128 + (Math.random() * 80 - 40),
                y: bowserY + 180,
                speed: 5 + Math.random() * 4,
                size: 64,
                angle: Math.random() * Math.PI * 2,
                spin: (Math.random() * 0.1 + 0.05) * (Math.random() < 0.5 ? 1 : -1)
            });
            sfx.banThrow.currentTime = 0;
            sfx.banThrow.volume = 0.1;
            sfx.banThrow.play();
        }
    }

    const spawnInterval = setInterval(spawnHammers, 700);

    // defeat animation state
    let defeatAngle = 0;
    let defeatX = 0;
    let defeatY = 0;
    let defeatSize = 256;

    function update() {
        ctx.clearRect(0, 0, canvas.width, canvas.height);

        if (!defeated) {
            // snake: left > down > right > down > left > down > right > down ...
            if (phase === 0) {
                bowserX -= SPEED;
                if (bowserX <= 0) { bowserX = 0; phase = 1; }
            } else if (phase === 1) {
                bowserY += SPEED;
                if (bowserY >= 200) { bowserY = 200; phase = 2; }
            } else if (phase === 2) {
                bowserX += SPEED;
                if (bowserX >= canvas.width - 256) { bowserX = canvas.width - 256; phase = 3; }
            } else if (phase === 3) {
                bowserY += SPEED;
                if (bowserY >= 400) { bowserY = 400; phase = 0; }
            }
            // keep bowser from falling off bottom
            if (bowserY > canvas.height - 256) bowserY = canvas.height - 256;
            ctx.drawImage(bowserImg, bowserX, bowserY, 256, 256);
        } else {
            // shrink, fly and spin to top-left corner
            defeatAngle += 0.25;
            defeatX += (0 - defeatX) * 0.07;
            defeatY += (0 - defeatY) * 0.07;
            defeatSize += (48 - defeatSize) * 0.06;

            ctx.save();
            ctx.translate(defeatX + defeatSize / 2, defeatY + defeatSize / 2);
            ctx.rotate(defeatAngle);
            ctx.drawImage(byeImg, -defeatSize / 2, -defeatSize / 2, defeatSize, defeatSize);
            ctx.restore();

            if (defeatSize < 52 && Math.abs(defeatX) < 4 && Math.abs(defeatY) < 4) {
                canvas.remove();
                return;
            }
        }

        const agent = agents?.[bonzi_guid];
        if (!agent) return requestAnimationFrame(update);

        // Collision with bowser body
        const ax = agent.x;
        const ay = agent.y;
        const aw = 200;
        const ah = 160;

        const hit = bowserX + 256 > ax && bowserX < ax + aw && bowserY + 256 > ay && bowserY < ay + ah;
        if (hit) {
            if (!agent._hasExploded) {
                agent._hasExploded = true;
                sfx.explode.play();
                socket.emit("bowser_hit", bonzi_guid);
                setTimeout(function(){
                    agent._hasExploded = false;
                }, 5000);
            }
        }

        for (let i = hammers.length - 1; i >= 0; i--) {
            const h = hammers[i];
            h.y += h.speed;
            h.angle += h.spin;

            ctx.save();
            ctx.translate(h.x + h.size / 2, h.y + h.size / 2);
            ctx.rotate(h.angle);
            ctx.drawImage(hammerImg, -h.size / 2, -h.size / 2, h.size, h.size);
            ctx.restore();

            const hit = h.x + h.size > ax && h.x < ax + aw && h.y + h.size > ay && h.y < ay + ah;
            if (hit) {
                if (!agent._hasExploded) {
                    agent._hasExploded = true;
                    sfx.explode.play();
                    socket.emit("bowser_hit", bonzi_guid);
                    setTimeout(function(){
                        agent._hasExploded = false;
                    }, 5000);
                }
            }

            if (h.y > canvas.height + 100) hammers.splice(i, 1);
        }

        // Bullet update + boss collision
        for (let i = bullets.length - 1; i >= 0; i--) {
            const b = bullets[i];
            b.y -= b.speed;

            ctx.fillStyle = "yellow";
            ctx.beginPath();
            ctx.arc(b.x, b.y, b.size / 2, 0, Math.PI * 2);
            ctx.fill();

            if (
                b.x > bowserX && b.x < bowserX + 256 &&
                b.y > bowserY && b.y < bowserY + 256 &&
                !spellCardActive
            ) {
                bullets.splice(i, 1);
                bossHP--;

                if (bossHP <= 0 && !spellCardActive) {
                    spellCardActive = true;
                    clearInterval(spawnInterval);
                    defeated = true;
                    defeatX = bowserX;
                    defeatY = bowserY;
                    socket.emit("bowserkilled", bonzi_guid);
                }

                continue;
            }

            if (b.y < -20) bullets.splice(i, 1);
        }
        requestAnimationFrame(update);
    }

    let loaded = 0;
    [bowserImg, byeImg, hammerImg].forEach(img => {
        img.onload = () => {
            loaded++;
            if (loaded === 3) update();
        };
    });

    document.addEventListener("keydown", (e) => {
        if (e.code === "Space") {
            const agent = agents?.[bonzi_guid];
            if (!agent._hasExploded) {
                socket.emit("bulletshoot");
                sfx.shoot.currentTime = 0;
                sfx.shoot.play();
            }
        }
    });
    socket.on("agent_bullet", (data) => {
        const agent = agents[data.id];
        if (!agent) return;

        bullets.push({
            x: agent.x + 100,
            y: agent.y,
            speed: 8,
            size: 16,
            id: data.id
        });
            sfx.shoot.currentTime = 0;
            sfx.shoot.play();
    });
}

