const hammers = [];

// wrecking ball pendulum physics
const anchorX = canvas.width / 2;
const anchorY = -40;
let ropeLen = 220; // initial rope length
const maxRope = canvas.height + 120;
let angle = Math.PI * 0.65; // start at 65 degrees (right side)
let aVel = 0;               // angular velocity
let bowserX = 0;
let bowserY = 0;

function spawnHammers() {
    if (defeated) return;
    const count = 1 + Math.floor(Math.random() * 2);
    for (let i = 0; i < count; i++) {
        hammers.push({
            x: bowserX + 128 + (Math.random() * 80 - 40),
            y: bowserY + 180,
            speed: 5 + Math.random() * 4,
            size: 64,
            angle: Math.random() * Math.PI * 2,
            spin: (Math.random() * 0.1 + 0.05) * (Math.random() < 0.5 ? 1 : -1)
        });
        sfx.banThrow.currentTime = 0;
        sfx.banThrow.volume = 0.1;
        sfx.banThrow.play();
    }
}

const spawnInterval = setInterval(spawnHammers, 700);

function update() {
    ctx.clearRect(0, 0, canvas.width, canvas.height);

    if (!defeated) {
        // real pendulum physics: faster at bottom, slower at edges
        ropeLen = Math.min(ropeLen + 0.35, maxRope);
        const g = 0.003; // gravity
        const aAcc = -(g / ropeLen) * Math.sin(angle);
        aVel += aAcc;
        aVel *= 0.9995; // tiny air resistance
        angle += aVel;

        bowserX = anchorX + ropeLen * Math.sin(angle) - 128;
        bowserY = anchorY + ropeLen * Math.cos(angle);

        // clamp to screen
        if (bowserX < 0) bowserX = 0;
        if (bowserX > canvas.width - 256) bowserX = canvas.width - 256;
        if (bowserY > canvas.height - 256) bowserY = canvas.height - 256;

        // draw chain
        const bossCX = bowserX + 128;
        const bossCY = bowserY + 128;
        ctx.strokeStyle = "#888";
        ctx.lineWidth = 3;
        ctx.beginPath();
        ctx.moveTo(anchorX, anchorY);
        ctx.lineTo(bossCX, bossCY);
        ctx.stroke();

        bossEl.style.left = bowserX + "px";
        bossEl.style.top = bowserY + "px";
    } else {
        // bye.gif shrinks, spins and flies to top-left
        const s = parseFloat(bossEl.style.width) || 256;
        const newS = s + (48 - s) * 0.06;
        const x = parseFloat(bossEl.style.left) || 0;
        const y = parseFloat(bossEl.style.top) || 0;
        const newX = x + (0 - x) * 0.07;
        const newY = y + (0 - y) * 0.07;
        bossEl.style.left = newX + "px";
        bossEl.style.top = newY + "px";
        bossEl.style.width = newS + "px";
        bossEl.style.height = newS + "px";
        if (newS < 52 && Math.abs(newX) < 4 && Math.abs(newY) < 4) {
            bossEl.remove();
            canvas.remove();
            return;
        }
    }

